import{_ as e,c as a,o as r,a4 as t}from"./chunks/framework.nQaBHiNx.js";const u=JSON.parse('{"title":"深入理解计算机系统","description":"","frontmatter":{},"headers":[],"relativePath":"computer/book/computer-system-a-programmer-perspective/index.md","filePath":"computer/book/computer-system-a-programmer-perspective/index.md"}'),i={name:"computer/book/computer-system-a-programmer-perspective/index.md"},o=t('<h1 id="深入理解计算机系统" tabindex="-1">深入理解计算机系统 <a class="header-anchor" href="#深入理解计算机系统" aria-label="Permalink to &quot;深入理解计算机系统&quot;">​</a></h1><p>本书主要介绍了计算机系统的基本概念，包括最底层的内存中的数据表示、流水线指令的构成、虚拟存储器、编译系统、动态加载库，以及用户应用等。书中提供了大量实际操作，可以帮助读者更好地理解程序执行的方式，改进程序的执行效率。此书以程序员的视角全面讲解了计算机系统，深入浅出地介绍了处理器、编译器、操作系统和网络环境，是这一领域的权威之作。</p><p>本书的最大优点是为程序员描述计算机系统的实现细节，帮助其在大脑中构造一个层次型的计算机系统，从最底层的数据在内存中的表示到流水线指令的构成，到虚拟存储器，到编译系统，到动态加载库，到最后的用户态应用。通过掌握程序是如何映射到系统上，以及程序是如何执行的，读者能够更好地理解程序的行为为什么是这样的，以及效率低下是如何造成的。</p><ul><li>第一章 计算机系统漫游</li><li>第二章 信息的表示和处理</li><li>第三章 程序的机器级表示</li><li>第四章 处理器体系结构</li><li>第五章 优化程序性能</li><li>第六章 存储器层次结构</li><li>第七章 链接</li><li>第八章 异常控制流</li><li>第九章 测量程序执行时间</li><li>第十章 虚拟内存</li><li>第十章 系统级 IO</li><li>第十一章 网络编程</li><li>第十二章 并发编程</li></ul><h2 id="学习资料" tabindex="-1">学习资料 <a class="header-anchor" href="#学习资料" aria-label="Permalink to &quot;学习资料&quot;">​</a></h2><h3 id="文字" tabindex="-1">文字 <a class="header-anchor" href="#文字" aria-label="Permalink to &quot;文字&quot;">​</a></h3><p><a href="https://book.douban.com/subject/26912767/" target="_blank" rel="noreferrer">豆瓣读书 - 《深入理解计算机系统》</a></p><p><a href="https://hansimov.gitbook.io/csapp/" target="_blank" rel="noreferrer">在线书籍 - 《深入理解计算机系统》</a></p><h3 id="视频" tabindex="-1">视频 <a class="header-anchor" href="#视频" aria-label="Permalink to &quot;视频&quot;">​</a></h3><p><a href="https://www.bilibili.com/video/BV1cD4y1D7uR/" target="_blank" rel="noreferrer">哔哩哔哩 - 《深入理解计算机系统》</a></p>',10),l=[o];function s(n,c,p,h,d,m){return r(),a("div",null,l)}const b=e(i,[["render",s]]);export{u as __pageData,b as default};
